// "auth-refactor.md" → "auth-refactor"
func DisplayName(filename string) string {
	return strings.TrimSuffix(filename, ".md")
}

// Rename renames a plan by giving it a new display name slug.
// It renames the .md file on disk (if it exists), rekeys the planstate entry,
// and persists the updated state.
// newName should be a human-readable name (e.g., "auth refactor") which will be
// slugified automatically. Returns the new filename on success.
func (ps *PlanState) Rename(oldFilename, newName string) (string, error) {
	entry, ok := ps.Plans[oldFilename]
	if !ok {
		return "", fmt.Errorf("plan not found: %s", oldFilename)
	}
	if newName == "" {
		return "", fmt.Errorf("new name cannot be empty")
	}

	// Build new filename from the slug alone.

	name = strings.ToLower(strings.TrimSpace(name))
	name = regexp.MustCompile(`[^a-z0-9]+`).ReplaceAllString(name, "-")
	return strings.Trim(name, "-")
}

// buildPlanFilename derives the plan filename from a human name.
// "Auth Refactor" → "auth-refactor.md"
func buildPlanFilename(name string, _ time.Time) string {
	slug := slugifyPlanName(name)
	if slug == "" {
		slug = "plan"
	}
	return slug + ".md"
}

// renderPlanStub returns the initial markdown content for a new plan file.
func renderPlanStub(name, description, filename string) string {
	return fmt.Sprintf("# %s\n\n## Context\n\n%s\n\n## Notes\n\n- Created by kas lifecycle flow\n- Plan file: %s\n", name, description, filename)
}
